const stadiumState = {
    alerts: {},
    attendance: {
        zone1: { current: 1150, capacity: 4000 },
        zone2: { current: 3990, capacity: 7000 },
        zone3: { current: 590, capacity: 3000 },
        zone4: { current: 5910, capacity: 6000 },
        global: 0,
        globalCapacity: 4000 + 7000 + 3000 + 6000,
    },
    lighting: {
        zone1: 100, zone2: 100, zone3: 100, zone4: 100
    },
    environment: {
        co2: 420, aqi: 25, temp: 24.5
    },
    power: {
        gridKW: 1800,
        gridVoltage: 230,
        gen1: { status: 'STANDBY', rpm: 0 },
        gen2: { status: 'ACTIF', rpm: 0 },
        gen3: { status: 'PANNE' }
    }
};

global.set('stadiumState', stadiumState);
msg.payload = stadiumState;
return msg;

let state = global.get('stadiumState');

// Ensure the alerts object exists
if (!state.alerts) {
    state.alerts = {};
}

// 1. Simulate Attendance (Increment until capacity)
['zone1', 'zone2', 'zone3', 'zone4'].forEach(zone => {
    if (state.attendance[zone].current < state.attendance[zone].capacity) {
        state.attendance[zone].current += Math.floor(Math.random() * 20);

        // Cap it exactly at capacity
        if (state.attendance[zone].current > state.attendance[zone].capacity) {
            state.attendance[zone].current = state.attendance[zone].capacity;
        }
    }
});

// Calculate Global Attendance
state.attendance.global = state.attendance.zone1.current + state.attendance.zone2.current + state.attendance.zone3.current + state.attendance.zone4.current;

// 2. Simulate Environment
state.environment.co2 += (Math.random() - 0.4) * 5; 
state.environment.temp += (Math.random() - 0.5) * 0.2;

// 3. Simulate Power (Simple fluctuations for charting)
state.power.gridKW += (Math.random() - 0.5) * 40;
state.power.gridKW = Math.max(1000, Math.min(2500, state.power.gridKW));
state.power.gridVoltage = 230 + (Math.random() - 0.5) * 4;

['gen1', 'gen2', 'gen3'].forEach(gen => {
    if (state.power[gen]) {
        if (state.power[gen].status === 'ACTIF') {
            // If active, fluctuate RPM around 1500
            state.power[gen].rpm = 1500 + Math.floor((Math.random() - 0.5) * 50);
        } else {
            // If STANDBY or PANNE, RPM is 0
            state.power[gen].rpm = 0;
        }
    }
});

// 4. Log Alerts to the State Object
// A. Dynamic Zone Attendance Alerts
['zone1', 'zone2', 'zone3', 'zone4'].forEach(zone => {
    if (state.attendance[zone].current >= state.attendance[zone].capacity) {
        let alertId = `capacity.${zone}`;
        if (!state.alerts[alertId]) {
            state.alerts[alertId] = { 
                msg: `CRITICAL: ${zone.toUpperCase()} at 100% Capacity!`, 
                treated: false,
                shown: false,
                type: 'security'
            };
        }
    }
});

// B. Grid Overload Warning
if (state.power.gridKW > 2200) {
    if (!state.alerts['power.grid_warning']) {
        state.alerts['power.grid_warning'] = {
            msg: `WARNING: Grid load high (${Math.round(state.power.gridKW)} kW)`,
            treated: false,
            shown: false,
            type: 'power'
        };
    }
}

// C. Generator Failure Alerts
['gen1', 'gen2', 'gen3'].forEach(gen => {
    if (state.power[gen].status === 'PANNE') {
        let alertId = `power.${gen}_failure`;
        if (!state.alerts[alertId]) {
            state.alerts[alertId] = { 
                msg: `URGENT: ${gen.toUpperCase()} is in PANNE state. Intervention required.`, 
                treated: false,
                shown: false,
                type: 'power'
            };
        }
    }
});

// Save back to global memory
global.set('stadiumState', state);

// 5. Output Routing (Splitting logic)
return [
    { payload: state.attendance },  // Pin 1: Attendance
    { payload: state.lighting },    // Pin 2: Lighting
    { payload: state.environment }, // Pin 3: HVAC
    { payload: state.power },       // Pin 4: Power
    { payload: state.alerts }       // Pin 5: Alerts
];

return [
    { payload: msg.payload.zone1.current },
    { payload: msg.payload.zone2.current },
    { payload: msg.payload.zone3.current },
    { payload: msg.payload.zone4.current },
];

let state = global.get('stadiumState');
state.lighting.zone1 = msg.payload;
global.set('stadiumState', state);
return msg;

let state = global.get('stadiumState');
state.lighting.zone2 = msg.payload;
global.set('stadiumState', state);
return msg;

let state = global.get('stadiumState');
state.lighting.zone3 = msg.payload;
global.set('stadiumState', state);
return msg;

let state = global.get('stadiumState');
state.lighting.zone4 = msg.payload;
global.set('stadiumState', state);
return msg;

let allAlerts = msg.payload;
let activeAlerts = [];

for (const [id, data] of Object.entries(allAlerts)) {
    if (data.treated === false) {
        activeAlerts.push({
            id: id,
            msg: data.msg,
            type: data.type
        });
    }
}

msg.payload = activeAlerts;
return msg;

let alertId = msg.payload; // e.g., "power.gen3_failure"
let state = global.get('stadiumState');

// If the alert exists, mark it as treated
if (state.alerts && state.alerts[alertId]) {
    state.alerts[alertId].treated = true;

    // Save the updated state back to memory
    global.set('stadiumState', state);
}

return msg;

let activeAlerts = msg.payload; 

let state = global.get('stadiumState');
let stateUpdated = false;
let messagesToSend = [];

activeAlerts.forEach(alert => {
    if (state.alerts[alert.id] && state.alerts[alert.id].shown === false) {

        messagesToSend.push({ topic: alert.type.toUpperCase(), payload: alert.msg });

        // Flip the flag in the global state
        state.alerts[alert.id].shown = true;
        stateUpdated = true;
    }
});

if (stateUpdated) {
    global.set('stadiumState', state);
}

if (messagesToSend.length > 0) {
    return [messagesToSend]; 
}

return null;

