let state = global.get('stadiumState');
if (!state) return null;

let p = (z) => state.attendance[z].current / state.attendance[z].capacity;
let l = (z) => Math.max(0.2, state.lighting[z] / 100);

msg.payload = [
    // Background Lighting (Brightness)
    { command: 'set_attribute', selector: '#lt_zone_1', attributeName: 'opacity', attributeValue: l('zone1') },
    { command: 'set_attribute', selector: '#lt_zone_2', attributeName: 'opacity', attributeValue: l('zone2') },
    { command: 'set_attribute', selector: '#lt_zone_3', attributeName: 'opacity', attributeValue: l('zone3') },
    { command: 'set_attribute', selector: '#lt_zone_4', attributeName: 'opacity', attributeValue: l('zone4') },

    // Attendance Dots (Revealed via Clipping Masks)
    { command: 'set_attribute', selector: '#att_zone1', attributeName: 'width',  attributeValue: Math.round(p('zone1') * 700) },
    { command: 'set_attribute', selector: '#att_zone3', attributeName: 'width',  attributeValue: Math.round(p('zone3') * 700) },
    { command: 'set_attribute', selector: '#att_zone2', attributeName: 'height', attributeValue: Math.round(p('zone2') * 510) },
    { command: 'set_attribute', selector: '#att_zone4', attributeName: 'height', attributeValue: Math.round(p('zone4') * 510) },

    { command: 'update_text', selector: '#total', text: state.attendance.global.toLocaleString() }
];
return msg;

return [
    { payload: msg.payload.zone1 },
    { payload: msg.payload.zone2 },
    { payload: msg.payload.zone3 },
    { payload: msg.payload.zone4 },
];

let state = global.get('stadiumState');
let targetLevel = msg.payload; // 100, 60, or 0

// Apply to all 4 spectator zones
state.lighting.zone1 = targetLevel;
state.lighting.zone2 = targetLevel;
state.lighting.zone3 = targetLevel;
state.lighting.zone4 = targetLevel;

global.set('stadiumState', state);

return msg;

// 1. Initialize fieldState (High Speed / Random Chaos Edition)
let fState = global.get('fieldState') || {
    players: {},
    ball: { x: 500, y: 375, holder: "p_mar_10" }
};

// 2. Playable Field Constraints
const field = { xMin: 250, xMax: 750, yMin: 220, yMax: 530 };

// 3. FULL RANDOM INITIALIZATION
// If fieldState is empty, scatter all 22 players anywhere on the pitch
if (Object.keys(fState.players).length === 0) {
    ['mar', 'sen'].forEach(team => {
        for (let i = 1; i <= 11; i++) {
            let id = `p_${team}_${i}`;
            // Completely random X and Y within the lines
            let randX = field.xMin + (Math.random() * (field.xMax - field.xMin));
            let randY = field.yMin + (Math.random() * (field.yMax - field.yMin));

            fState.players[id] = {
                x: randX,
                y: randY,
                homeX: randX,
                homeY: randY
            };
        }
    });
    fState.ball.holder = "p_mar_10";
}

let commands = [];

// 4. POSSESSION & HIGH-SPEED PASSING
// 30% chance to pass every second (Double the previous speed)
if (Math.random() < 0.30) {
    const allIds = Object.keys(fState.players);
    fState.ball.holder = allIds[Math.floor(Math.random() * allIds.length)];
}

let holder = fState.players[fState.ball.holder];
fState.ball.x = holder.x + 5;
fState.ball.y = holder.y + 5;

commands.push({ command: 'update_attribute', selector: '#ball', attributeName: 'cx', attributeValue: Math.round(fState.ball.x) });
commands.push({ command: 'update_attribute', selector: '#ball', attributeName: 'cy', attributeValue: Math.round(fState.ball.y) });

// 5. HIGH-SPEED ZONAL MOVEMENT
Object.keys(fState.players).forEach(id => {
    let p = fState.players[id];

    // Players shift 25% toward the ball (Aggressive attraction)
    let targetX = p.homeX + (fState.ball.x - 500) * 0.25;
    let targetY = p.homeY + (fState.ball.y - 375) * 0.25;

    // Movement speed multiplier (increased from 0.1 to 0.4)
    // Plus higher random jitter (up to 12px jumps)
    p.x += (targetX - p.x) * 0.4 * Math.random() + (Math.random() - 0.5) * 20;
    p.y += (targetY - p.y) * 0.4 * Math.random() + (Math.random() - 0.5) * 20;

    // Hard boundary enforcement
    p.x = Math.max(field.xMin, Math.min(field.xMax, p.x));
    p.y = Math.max(field.yMin, Math.min(field.yMax, p.y));

    commands.push({
        command: 'update_attribute',
        selector: `#${id}`,
        attributeName: 'transform',
        attributeValue: `translate(${Math.round(p.x)}, ${Math.round(p.y)})`
    });
});

global.set('fieldState', fState);
msg.payload = commands;
return msg;
